    {"term": "Water activity (Aw)", "defn": "A 0–1 measure of free water available to microbes; keeping Aw <=0.55–0.65 suppresses mould and yeast growth.", "tags": ['reference']},
    {"term": "CCP (Critical Control Point)", "defn": "A process step with a measured limit that prevents a specific hazard; HACCP terminology used for in-process control.", "tags": ['reference']},
    {"term": "Batch / lot", "defn": "One defined production run carrying a single ID that follows the material through every transfer.", "tags": ['reference']},
