    {"term": "ALCOA+", "defn": "Data-integrity rule: records must be Attributable, Legible, Contemporaneous, Original, Accurate, plus Complete, Consistent, Enduring, Available.", "tags": ['reference']},
    {"term": "V-model (DQ/IQ/OQ/PQ)", "defn": "Equipment qualification framework tying each design stage to a matching verification: Design, Installation, Operational, and Performance Qualification.", "tags": ['reference']},
    {"term": "MACO", "defn": "Maximum Allowable Carryover, the calculated residue limit used as the acceptance criterion in cleaning validation.", "tags": ['reference']},
    {"term": "EM (Environmental Monitoring)", "defn": "The program that samples non-viable particles, viable air, surfaces, and personnel against alert and action limits.", "tags": ['reference']},
    {"term": "GACP", "defn": "Good Agricultural and Collection Practice, the upstream cultivation/drying standard that feeds compliant biomass into the GMP facility.", "tags": ['reference']},
