    {"term": "Floor plan", "defn": "The architect's flat, top-down drawing of walls, doors and rooms, usually dimensioned in millimetres.", "tags": ['precision']},
    {"term": "Render", "defn": "To draw the 3D scene as a picture on screen; done many times a second to make it interactive.", "tags": ['precision']},
