    {"term": "JSON / data file", "defn": "A plain, human-readable list of facts (room names, sizes, positions) that the code reads to build the model.", "tags": ['precision']},
    {"term": "Schema", "defn": "The agreed shape of the data file, here just four record types: rooms, walls, equipment and devices.", "tags": ['precision']},
