    {"term": "PTZ camera", "defn": "A pan-tilt-zoom camera that can swivel and zoom to track movement, used here for roof-intrusion coverage.", "tags": ['precision']},
    {"term": "glTF", "defn": "A standard 3D file format for importing detailed models authored in tools like Blender, or exporting the building back out.", "tags": ['precision']},
