    {"term": "GACP (Good Agricultural and Collection Practice)", "defn": "The cultivation and collection standard applied to medicinal-cannabis starting material, recognising it as a botanical crop before it becomes a medicine.", "tags": ['reference']},
    {"term": "QMS / PQS (Quality Management System / Pharmaceutical Quality System)", "defn": "The organised set of responsibilities, procedures, processes and resources by which an organisation directs and controls quality; used interchangeably in the manual.", "tags": ['reference']},
