    {"term": "GDP (Good Documentation Practice)", "defn": "Rules for making and correcting records: contemporaneous, indelible, original preserved, corrections by a single legible line that is initialled, dated and reasoned.", "tags": ['reference']},
    {"term": "CAPA (Corrective and Preventive Action)", "defn": "A root-cause-driven process to fix an existing problem (corrective) and stop it recurring or occurring (preventive).", "tags": ['reference']},
    {"term": "Change Control", "defn": "The formal process for assessing, approving and implementing any change that could affect product quality or the validated state.", "tags": ['reference']},
